section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/drift-classification-taxonomy.json",
  "type": "object",
  "required": [
    "drift_id",
    "environment",
    "resource_address",
    "detected_at",
    "class",
    "evidence",
    "fix_action",
    "fix_pr_url",
    "triage_owner",
    "triage_at"
  ],
  "properties": {
    "drift_id": {
      "type": "string",
      "description": "string"
    },
    "environment": {
      "type": "string",
      "description": "string"
    },
    "resource_address": {
      "type": "string",
      "description": "string (TF address)"
    },
    "detected_at": {
      "type": "string",
      "description": "string (ISO-8601)"
    },
    "class": {
      "type": "string",
      "description": "enum (hand_edit | external_automation | vendor_change | legitimate_emergency | unknown)"
    },
    "evidence": {
      "type": "object",
      "description": "object (source + reference)"
    },
    "fix_action": {
      "type": "string",
      "description": "enum (revert | backport | provider_bump | boundary_review | triage)"
    },
    "fix_pr_url": {
      "type": "string",
      "description": "string (null if not yet open)"
    },
    "triage_owner": {
      "type": "string",
      "description": "string"
    },
    "triage_at": {
      "type": "string",
      "description": "string (ISO-8601)"
    }
  }
}
